24	interface Policy {
25	  items: any[];
26	  cap: number;
27	  payoutSoFar: number;
28	}
29	
30	export function processScenario(input: any): unknown {
31	  const results: Array<{ premium: number } | { payout: number; remainingCap: number }> = [];
32	  const policies: Policy[] = [];
33	  let quoteCount = 0;
34	  for (const step of input.steps) {
35	    if (step.op === "claim") {
36	      const policy = policies[step.policy];
37	      const policyCountsByType: Record<string, number> = {};
38	      for (const it of policy.items) {
39	        policyCountsByType[it.type] = (policyCountsByType[it.type] ?? 0) + 1;
40	      }
41	      const damageCountsByType: Record<string, number> = {};
42	      for (const d of step.incident.damages) {
43	        damageCountsByType[d.itemType] = (damageCountsByType[d.itemType] ?? 0) + 1;
44	      }
45	      for (const [type, count] of Object.entries(damageCountsByType)) {
46	        if (count > (policyCountsByType[type] ?? 0)) {
47	          throw new Error(`Claim has more ${type} entries than policy covers`);
48	        }
49	      }
50	      let payout = 0;
51	      for (const damage of step.incident.damages) {
52	        const item = policy.items.find((it) => it.type === damage.itemType);
53	        let reimbursement: number;
54	        if (item.enchantment >= 8) {
55	          reimbursement = damage.amount * 0.5;
56	        } else if (item.material === "dragon") {
57	          reimbursement = damage.amount;
58	        } else {
59	          reimbursement = damage.amount;
60	        }
61	        payout += Math.floor(reimbursement - DEDUCTIBLE);
62	      }
63	      const remainingBefore = policy.cap - policy.payoutSoFar;
64	      if (payout > remainingBefore) payout = remainingBefore;
65	      policy.payoutSoFar += payout;
66	      results.push({ payout, remainingCap: Math.max(0, policy.cap - policy.payoutSoFar) });
67	      continue;
68	    }
69	    const items = step.items;
70	    const insuranceSum = items.reduce((s: number, it: any) => s + (INSURANCE_VALUE_BY_TYPE[it.type] ?? 0), 0);
71	    policies.push({ items, cap: 2 * insuranceSum, payoutSoFar: 0 });
72	    if (items.length === 0) {
73	      results.push({ premium: PROCESSING_FEE });
74	      quoteCount++;
75	      continue;
76	    }
77	    const countsByType: Record<string, number> = {};
78	    for (const item of items) {
79	      countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
80	    }
81	    let basePremium = 0;
82	    for (const [type, count] of Object.entries(countsByType)) {
83	      if ((type === "rune" || type === "moonstone") && count === 3) {
84	        basePremium += 60;
85	      } else {
86	        basePremium += count * BASE_PREMIUM_BY_TYPE[type];
87	      }
88	    }
89	    let itemSurcharges = 0;
90	    for (const item of items) {
91	      if (item.cursed) {
92	        itemSurcharges += BASE_PREMIUM_BY_TYPE[item.type] * 0.5;
93	      }
94	      if (item.enchantment >= 5) {
95	        itemSurcharges += BASE_PREMIUM_BY_TYPE[item.type] * 0.3;
96	      }
97	    }
98	    const loyaltyDiscount = input.customer.yearsWithMHPCO >= 2 ? basePremium * 0.2 : 0;
99	    const followUpDiscount = quoteCount > 0 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
100	    const premium = Math.ceil(basePremium + itemSurcharges + basePremium * FIRST_INSURANCE_RATE - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
101	    results.push({ premium });
102	    quoteCount++;
103	  }
104	  return { results };
105	}
